import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './CampaignDetail.css';

const CATEGORY_EMOJI = {
  Medical: '🏥', Education: '📚', Social: '🤝',
  Environment: '🌿', 'Animal Welfare': '🐾',
  'Disaster Relief': '⛑️', Other: '💡'
};

const PRESET_AMOUNTS = [100, 500, 1000, 2500, 5000];

const CampaignDetail = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, isAuthenticated } = useAuth();

  const [campaign, setCampaign] = useState(null);
  const [donations, setDonations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [donationsLoading, setDonationsLoading] = useState(true);
  const [error, setError] = useState('');
  const [donateAmount, setDonateAmount] = useState('');
  const [donateError, setDonateError] = useState('');
  const [donateLoading, setDonateLoading] = useState(false);
  const [donateSuccess, setDonateSuccess] = useState('');

  const fetchCampaign = useCallback(async () => {
    try {
      setLoading(true);
      setError('');
      const { data } = await axios.get(`/api/campaigns/${id}`);
      setCampaign(data.campaign);
    } catch (err) {
      setError(err.response?.status === 404
        ? 'Campaign not found.'
        : err.response?.data?.message || 'Failed to load campaign.');
    } finally {
      setLoading(false);
    }
  }, [id]);

  const fetchDonations = useCallback(async () => {
    try {
      setDonationsLoading(true);
      const { data } = await axios.get(`/api/donations/${id}`);
      setDonations(data.donations);
    } catch {
      // Non-critical — silently fail
    } finally {
      setDonationsLoading(false);
    }
  }, [id]);

  useEffect(() => {
    fetchCampaign();
    fetchDonations();
  }, [fetchCampaign, fetchDonations]);

  const handleDonate = async () => {
    if (!isAuthenticated()) { navigate('/login'); return; }

    const amount = Number(donateAmount);
    if (!donateAmount || isNaN(amount) || amount < 1) {
      setDonateError('Please enter a valid donation amount (minimum ₹1).'); return;
    }
    if (amount > 500000) {
      setDonateError('Maximum donation is ₹5,00,000 per transaction.'); return;
    }

    try {
      setDonateLoading(true);
      setDonateError('');
      setDonateSuccess('');

      // Step 1 — Create Razorpay order via backend
      const { data: orderData } = await axios.post('/api/donations/create-order', {
        amount,
        campaignId: id
      });

      // Step 2 — Open Razorpay checkout
      const razorpayKey = process.env.REACT_APP_RAZORPAY_KEY || orderData.key;

      if (typeof window.Razorpay === 'undefined') {
        throw new Error('Razorpay script failed to load. Please refresh and try again.');
      }

      const options = {
        key: razorpayKey,
        amount: orderData.amount,
        currency: orderData.currency,
        name: 'FundIt',
        description: `Donation to: ${campaign.title}`,
        order_id: orderData.orderId,
        prefill: { name: user.name, email: user.email },
        theme: { color: '#1a56db' },
        notes: { campaignTitle: campaign.title },
        handler: async (response) => {
          // Step 3 — Record payment in DB
          try {
            await axios.post('/api/donations/record', {
              campaignId: id,
              amount,
              paymentId: response.razorpay_payment_id,
              orderId: response.razorpay_order_id
            });
            setDonateSuccess(
              `🎉 Thank you ${user.name}! Your donation of ₹${amount.toLocaleString('en-IN')} was successful.`
            );
            setDonateAmount('');
            await fetchCampaign();
            await fetchDonations();
          } catch {
            setDonateError(
              `Payment succeeded (ID: ${response.razorpay_payment_id}) but recording failed. Please contact support.`
            );
          } finally {
            setDonateLoading(false);
          }
        },
        modal: {
          ondismiss: () => {
            setDonateLoading(false);
            setDonateError('Payment was cancelled. You were not charged.');
          }
        }
      };

      const rzp = new window.Razorpay(options);
      rzp.on('payment.failed', (response) => {
        setDonateLoading(false);
        setDonateError(`Payment failed: ${response.error.description || 'Unknown error.'}. Please try again.`);
      });
      rzp.open();
    } catch (err) {
      setDonateLoading(false);
      setDonateError(err.response?.data?.message || err.message || 'Failed to initiate payment.');
    }
  };

  // ── Loading / Error states ─────────────────────────────────
  if (loading) {
    return (
      <div className="loading-state" style={{ minHeight: '60vh' }}>
        <div className="spinner spinner-lg" />
        <p style={{ color: 'var(--text-secondary)' }}>Loading campaign...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container" style={{ paddingTop: '4rem', textAlign: 'center' }}>
        <div className="alert alert-error" style={{ maxWidth: '500px', margin: '0 auto 2rem' }}>
          <span>⚠️</span>
          <p>{error}</p>
        </div>
        <Link to="/" className="btn btn-primary" id="btn-back-home">← Back to Campaigns</Link>
      </div>
    );
  }

  // ── Computed values ────────────────────────────────────────
  const progress = Math.min(Math.round((campaign.raised / campaign.goal) * 100), 100);
  const remaining = Math.max(campaign.goal - campaign.raised, 0);
  const isGoalReached = campaign.raised >= campaign.goal;
  const createdDate = new Date(campaign.createdAt).toLocaleDateString('en-IN', {
    year: 'numeric', month: 'long', day: 'numeric'
  });
  const donateAmountNum = Number(donateAmount);

  return (
    <div className="campaign-detail-page">
      <div className="container">
        <div className="detail-layout">

          {/* ── Left: Main Content ───────────────────────────── */}
          <div className="detail-main">

            {/* Breadcrumb */}
            <div className="breadcrumb" id="detail-breadcrumb">
              <Link to="/">Campaigns</Link>
              <span className="breadcrumb-sep">/</span>
              <span className="badge badge-blue">{campaign.category}</span>
            </div>

            {/* Hero Image */}
            <div className="detail-image-wrapper" id="campaign-hero-image">
              {campaign.imageUrl ? (
                <img
                  src={campaign.imageUrl}
                  alt={campaign.title}
                  className="detail-image"
                  onError={(e) => {
                    e.target.onerror = null;
                    e.target.src = `https://picsum.photos/seed/${id}/900/450`;
                  }}
                />
              ) : (
                <div className="detail-image-placeholder">
                  {CATEGORY_EMOJI[campaign.category] || '💡'}
                </div>
              )}
              {isGoalReached && (
                <div className="goal-reached-badge" id="goal-reached-badge">
                  ✅ Goal Reached!
                </div>
              )}
            </div>

            {/* Info Card */}
            <div className="detail-info-card" id="campaign-info-card">
              <h1 className="detail-title" id="campaign-detail-title">
                {campaign.title}
              </h1>

              <div className="detail-meta">
                <span className="meta-chip">
                  👤 By <strong>&nbsp;{campaign.creator?.name || 'Anonymous'}</strong>
                </span>
                <span className="meta-chip">📅 {createdDate}</span>
                <span className="badge badge-blue">{campaign.category}</span>
              </div>

              <div className="detail-description" id="campaign-description-text">
                {campaign.description.split('\n').map((para, i) => (
                  para.trim() ? <p key={i}>{para}</p> : null
                ))}
              </div>
            </div>

            {/* Donors List */}
            <div className="donors-card" id="donors-section">
              <h2 className="donors-card-title">
                💙 {donations.length} Supporter{donations.length !== 1 ? 's' : ''}
              </h2>

              {donationsLoading ? (
                <div style={{ display: 'flex', justifyContent: 'center', padding: '1.5rem' }}>
                  <div className="spinner spinner-blue" />
                </div>
              ) : donations.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '1.5rem', color: 'var(--text-muted)', fontSize: '0.9rem' }}>
                  🌟 Be the first person to support this campaign!
                </div>
              ) : (
                <div className="donors-list" id="donors-list">
                  {donations.map((d) => (
                    <div key={d._id} className="donor-row">
                      <div className="donor-avatar">
                        {(d.donor?.name || 'A').charAt(0).toUpperCase()}
                      </div>
                      <div className="donor-info">
                        <div className="donor-name">{d.donor?.name || 'Anonymous'}</div>
                        <div className="donor-date">
                          {new Date(d.createdAt).toLocaleDateString('en-IN', {
                            month: 'short', day: 'numeric', year: 'numeric'
                          })}
                        </div>
                      </div>
                      <div className="donor-amount">
                        ₹{d.amount.toLocaleString('en-IN')}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* ── Right: Sticky Sidebar ────────────────────────── */}
          <div className="donation-sidebar" id="donation-sidebar">

            {/* Progress Card */}
            <div className="progress-card" id="progress-card">
              <div className="raised-amount-display" id="raised-display">
                ₹{campaign.raised.toLocaleString('en-IN')}
              </div>
              <div className="raised-of-goal">
                raised of ₹{campaign.goal.toLocaleString('en-IN')} goal
              </div>

              <div className="progress-bar-wrapper" style={{ height: '10px' }}>
                <div
                  className="progress-bar-fill"
                  style={{ width: `${progress}%` }}
                  id="campaign-progress-bar"
                  role="progressbar"
                  aria-valuenow={progress}
                  aria-valuemin="0"
                  aria-valuemax="100"
                />
              </div>

              <div className="progress-stats-row" id="progress-stats">
                <div className="p-stat">
                  <span className="p-stat-val" style={{ color: 'var(--primary)' }}>{progress}%</span>
                  <span className="p-stat-label">Funded</span>
                </div>
                <div className="p-stat">
                  <span className="p-stat-val">{donations.length}</span>
                  <span className="p-stat-label">Donors</span>
                </div>
                <div className="p-stat">
                  <span className="p-stat-val" style={{ fontSize: '0.85rem' }}>
                    ₹{remaining.toLocaleString('en-IN')}
                  </span>
                  <span className="p-stat-label">Left</span>
                </div>
              </div>
            </div>

            {/* Donate Card */}
            <div className="donate-form-card" id="donate-form-card">
              <h3 className="donate-form-title">💙 Make a Donation</h3>

              {donateSuccess && (
                <div className="alert alert-success" id="donate-success" role="alert">
                  <span>🎉</span>
                  <p>{donateSuccess}</p>
                </div>
              )}

              {donateError && (
                <div className="alert alert-error" id="donate-error" role="alert">
                  <span>⚠️</span>
                  <p>{donateError}</p>
                </div>
              )}

              {!isAuthenticated() ? (
                <>
                  <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '1rem' }}>
                    Sign in to support this campaign.
                  </p>
                  <Link to="/login" className="login-to-donate-btn" id="btn-login-to-donate">
                    🔐 Sign In to Donate
                  </Link>
                </>
              ) : (
                <>
                  {/* Preset amounts */}
                  <div className="preset-grid" id="preset-amounts">
                    {PRESET_AMOUNTS.map((amt) => (
                      <button
                        key={amt}
                        id={`preset-${amt}`}
                        className={`preset-btn ${donateAmount === String(amt) ? 'preset-btn-active' : ''}`}
                        onClick={() => { setDonateAmount(String(amt)); setDonateError(''); setDonateSuccess(''); }}
                        type="button"
                      >
                        ₹{amt.toLocaleString('en-IN')}
                      </button>
                    ))}
                  </div>

                  {/* Custom amount */}
                  <span className="custom-amount-label">Or enter custom amount</span>
                  <div className="amount-input-wrapper">
                    <span className="amount-prefix">₹</span>
                    <input
                      id="donate-amount-input"
                      type="number"
                      className="amount-input"
                      placeholder="Enter amount"
                      value={donateAmount}
                      onChange={(e) => {
                        setDonateAmount(e.target.value);
                        setDonateError('');
                        setDonateSuccess('');
                      }}
                      min={1}
                      max={500000}
                    />
                  </div>

                  {/* Summary */}
                  {donateAmountNum > 0 && (
                    <div className="donate-summary-row" id="donation-summary">
                      <span>You are donating</span>
                      <strong>₹{donateAmountNum.toLocaleString('en-IN')}</strong>
                    </div>
                  )}

                  {/* Donate button */}
                  <button
                    className="donate-cta-btn"
                    id="btn-donate-now"
                    onClick={handleDonate}
                    disabled={donateLoading || !donateAmount || donateAmountNum < 1}
                  >
                    {donateLoading ? (
                      <><span className="spinner" /> Processing...</>
                    ) : (
                      '💚 Donate via Razorpay'
                    )}
                  </button>

                  <div className="secure-badge" id="secure-badge">
                    🔒 100% Secure · Powered by Razorpay
                  </div>
                </>
              )}
            </div>

            {/* Share Card */}
            <div className="share-card" id="share-card">
              <p className="share-card-title">📣 Share & Spread the Word</p>
              <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '0.875rem' }}>
                Help reach more people by sharing on social media.
              </p>
              <div className="share-buttons">
                <button
                  className="share-btn share-wa"
                  id="btn-share-whatsapp"
                  onClick={() => window.open(
                    `https://wa.me/?text=${encodeURIComponent(`💙 Support "${campaign.title}" on FundIt: ${window.location.href}`)}`
                  )}
                >
                  📱 WhatsApp
                </button>
                <button
                  className="share-btn share-tw"
                  id="btn-share-twitter"
                  onClick={() => window.open(
                    `https://twitter.com/intent/tweet?text=${encodeURIComponent(`Help fund "${campaign.title}" 💙`)}&url=${encodeURIComponent(window.location.href)}`
                  )}
                >
                  🐦 Twitter
                </button>
                <button
                  className="share-btn share-copy"
                  id="btn-copy-link"
                  onClick={() => {
                    navigator.clipboard.writeText(window.location.href);
                    alert('Link copied to clipboard!');
                  }}
                >
                  🔗 Copy Link
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CampaignDetail;
